14428 void BoUpSLP::computeMinimumValueSizes() {
14429   // We only attempt to truncate integer expressions.
14430   bool IsStoreOrInsertElt =
14431       VectorizableTree.front()->getOpcode() == Instruction::Store ||
14432       VectorizableTree.front()->getOpcode() == Instruction::InsertElement;
14433   if ((IsStoreOrInsertElt || UserIgnoreList) &&
14434       ExtraBitWidthNodes.size() <= 1 &&
14435       (!CastMaxMinBWSizes || CastMaxMinBWSizes->second == 0 ||
14436        CastMaxMinBWSizes->first / CastMaxMinBWSizes->second <= 2))
14437     return;
