14439   unsigned NodeIdx = 0;
14440   if (IsStoreOrInsertElt &&
14441       VectorizableTree.front()->State != TreeEntry::NeedToGather)
14442     NodeIdx = 1;
14443 
14444   // Ensure the roots of the vectorizable tree don't form a cycle.
14445   if (VectorizableTree[NodeIdx]->State == TreeEntry::NeedToGather ||
14446       (NodeIdx == 0 && !VectorizableTree[NodeIdx]->UserTreeIndices.empty()) ||
14447       (NodeIdx != 0 && any_of(VectorizableTree[NodeIdx]->UserTreeIndices,
14448                               [NodeIdx](const EdgeInfo &EI) {
